    def _get_allowed_employees(self, training_data_path):
        """Get allowlist of employee directories"""
        try:
            with open(os.path.join(training_data_path, 'allowed_employees.txt'), 'r') as f:
                allowed = [line.strip() for line in f if line.strip()]
                return [name for name in allowed if self._is_valid_employee_name(name)]
        except FileNotFoundError:
            # Fallback to directory listing with validation
            return [d for d in os.listdir(training_data_path) 
                   if os.path.isdir(os.path.join(training_data_path, d)) 
                   and self._is_valid_employee_name(d)]
    
    def _is_valid_employee_name(self, name):
        """Validate employee name to prevent path traversal"""
        if not name or len(name) > 100:
            return False
        # Only allow alphanumeric, underscore, and hyphen
        return all(c.isalnum() or c in ('_', '-') for c in name)
    
    def _allowed_file(self, filename):
        """Check if file extension is allowed"""
        return '.' in filename and \
               filename.rsplit('.', 1)[1].lower() in ALLOWED_EXTENSIONS
    
    def _load_and_validate_image(self, image_path):
        """Securely load and validate image"""
        # Read file with size limit
        max_size = 10 * 1024 * 1024  # 10MB
        file_size = os.path.getsize(image_path)
        
        if file_size > max_size:
            raise ValueError("Image file too large")
        
        # Load image with PIL for validation
        with Image.open(image_path) as img:
            # Validate image format
            if img.format not in ['JPEG', 'PNG']:
                raise ValueError("Invalid image format")
            
            # Limit image dimensions
            max_dimension = 4096
            if img.width > max_dimension or img.height > max_dimension:
                raise ValueError("Image dimensions too large")
            
            # Convert to RGB
            img = img.convert('RGB')
            
            # Convert to numpy array
            return np.array(img)
    
